sql.where:
1 = 1

    AND (
        d.conversation_key LIKE CONCAT('%', #{keyword}, '%')
        OR d.channel LIKE CONCAT('%', #{keyword}, '%')
        OR d.event_type LIKE CONCAT('%', #{keyword}, '%')
        OR d.status LIKE CONCAT('%', #{keyword}, '%')
    )


    AND d.event_type = #{eventType}


    AND d.status = #{status}


    AND d.target_user_id = #{targetUserId}


    AND d.message_id = #{messageId}
